import math

input = sys.stdin.read
data = input().split()

index = 0
t = int(data[index])
index += 1

for _ in range(t):
    n = int(data[index])
    index += 1
    a = [int(data[index + i]) for i in range(n)]
    index += n

    cnt = [0] * 30
    for val in a:
        for b in range(30):
            if val & (1 << b):
                cnt[b] += 1

    G = cnt[0]
    for b in range(1, 30):
        G = math.gcd(G, cnt[b])

    if G == 0:
        ans = list(range(1, n + 1))
    else:
        divisors = []
        sq = int(math.sqrt(G)) + 1
        for i in range(1, sq):
            if G % i == 0:
                divisors.append(i)
                if i != G // i:
                    divisors.append(G // i)
        divisors.sort()
        ans = [d for d in divisors if d <= n]

    print(' '.join(map(str, ans)))

